export function useMouse() {
  const x = ref(0), y = ref(0);
  const move = (e) => { x.value = e.x; y.value = e.y; };
  onMounted(() => window.addEventListener('mousemove', move));
  onUnmounted(() => window.removeEventListener('mousemove', move));
  return { x, y };
}

